class Solution:
    def colorTheArray(self, n: int, queries: List[List[int]]) -> List[int]:
        nums = [0] * n
        res = []
        count = 0

        for index, color in queries:
            old_color = nums[index]
            nums[index] = color

            # Check left neighbor
            if index > 0:
                if old_color != 0 and nums[index - 1] == old_color:
                    count -= 1
                if nums[index - 1] == color:
                    count += 1

            # Check right neighbor
            if index < n - 1:
                if old_color != 0 and nums[index + 1] == old_color:
                    count -= 1
                if nums[index + 1] == color:
                    count += 1

            res.append(count)

        return res
